              {activeCall.type === 'VIDEO' && (
                  <div className="absolute inset-0 bg-gradient-to-b from-slate-800 to-black opacity-50">
                      <div className="w-full h-full flex items-center justify-center">
                          <UserCheck size={120} className="opacity-20"/>
                      </div>
                  </div>
              )}

              <div className="relative z-10 flex flex-col items-center gap-8">
                  <div className="w-32 h-32 rounded-full bg-slate-800 border-4 border-slate-700 flex items-center justify-center shadow-2xl overflow-hidden relative">
                      <span className="text-4xl font-black">{activeCustomer.fullName.charAt(0)}</span>
                      {activeCall.status === 'RINGING' && <div className="absolute inset-0 border-4 border-emerald-500 rounded-full animate-ping"></div>}
                  </div>

                  <div className="text-center space-y-2">
                      <h2 className="text-4xl font-black tracking-tighter">
                          {activeCall.status === 'RINGING' ? 'Diyetisyen Arıyor...' : activeCall.hostName}
                      </h2>
                      <p className="text-emerald-400 font-bold uppercase tracking-widest animate-pulse">
                          {activeCall.status === 'RINGING' ? 'Gelen Arama' : 'Canlı Bağlantı'}
                      </p>
                  </div>

                  <div className="flex items-center gap-6 mt-10">
                      {activeCall.status === 'RINGING' ? (
                          <>
                             <button onClick={endCall} className="p-6 rounded-full bg-rose-500 hover:bg-rose-600 transition-all shadow-xl">
                                <PhoneOff size={32} fill="white" />
                             </button>
                             <button onClick={answerCall} className="p-6 rounded-full bg-emerald-500 hover:bg-emerald-600 transition-all shadow-xl animate-bounce">
                                <Phone size={32} fill="white" />
                             </button>
                          </>
                      ) : (
                          <>
                             <button className="p-6 rounded-full bg-white/10 hover:bg-white/20 transition-all backdrop-blur-md"><Mic size={24}/></button>
                             {activeCall.type === 'VIDEO' && <button className="p-6 rounded-full bg-white/10 hover:bg-white/20 transition-all backdrop-blur-md"><Video size={24}/></button>}
                             <button onClick={endCall} className="p-8 rounded-full bg-rose-500 hover:bg-rose-600 transition-all shadow-xl hover:scale-110 active:scale-95">
                                <PhoneOff size={32} fill="white" />
                             </button>
                          </>
                      )}
                  </div>
              </div>
          </div>
      )}

      {/* Sidebar Navigation */}
      <div className="w-24 m-4 bg-slate-900 rounded-[3rem] flex flex-col items-center py-10 gap-8 shadow-2xl z-20">
         <div className="w-12 h-12 bg-white/10 rounded-full flex items-center justify-center text-white font-black text-lg">
            {activeCustomer.fullName.charAt(0)}
         </div>
         <nav className="flex-1 flex flex-col gap-6 w-full px-2">
            {[
              { id: 'HOME', icon: User },
              { id: 'DIET', icon: Apple },
