    <button 
        onClick={onClick}
        className={`px-6 py-3 rounded-[1.5rem] text-[10px] font-black uppercase tracking-widest flex items-center gap-2 whitespace-nowrap transition-all ${active ? 'bg-slate-900 text-white shadow-lg scale-105' : 'bg-white text-slate-500 hover:text-slate-900'}`}
    >
        {Icon && <Icon size={14} className={alert ? 'text-rose-500 animate-pulse' : ''} />}
        {label}
    </button>
);

const GiftIcon = ({ filled }: { filled: boolean }) => (
    <Gift size={20} className={filled ? "animate-bounce" : ""} />
);

import React, { useState, useEffect, useRef } from 'react';
import { useSalon } from '../store/SalonContext';
import { UserRole, Customer, DietDay, ChatMessage, DietMeal } from '../types';
import { 
  Apple, Search, MessageCircle, Edit, Save, 
  Send, Image as ImageIcon, Phone, Eye, EyeOff, 
  UserCheck, ShieldCheck, ChevronRight, Lock, Unlock, FileText, Activity, Scale,
  Video, Mic, MicOff, VideoOff, PhoneOff, Clock, Calendar, X, Settings, TrendingUp,
  Trash2, Copy, RefreshCw, Droplets, Plus, Minus, User, Flame, Utensils, Zap, Camera,
  FilePlus, ClipboardList
} from 'lucide-react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, LineChart, Line, Legend } from 'recharts';

interface DietitianCockpitProps {
  setTab: (tab: string) => void;
}

