  DETOX: {
    name: 'Hızlı Ödem Atıcı (Detoks)',
    days: ['Pazartesi', 'Salı', 'Çarşamba', 'Perşembe', 'Cuma', 'Cumartesi', 'Pazar'].map(d => ({
      dayName: d,
