            <div className="animate-in slide-in-from-bottom-10 space-y-10">
                <h2 className={`text-5xl font-black italic mb-8 ${tierTheme.text}`}>Sadakat Kartları</h2>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
