                                        <Star size={24} />
                                    </div>
                                    <div>
                                        <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-1">{rec.reason}</p>
                                        <h4 className="text-xl font-black text-slate-900 italic">{services.find(s => s.id === rec.serviceId)?.name || 'Özel Bakım'}</h4>
                                    </div>
                                </div>
                            ))}
