                                                               <span className="text-[10px] font-bold text-slate-400">{meal.calories || 0} kcal</span>
                                                           </div>
                                                           <p className="text-sm font-medium text-slate-700 leading-snug">{meal.content || '-'}</p>
                                                       </div>
