                                                   </div>
                                               </div>
                                           )}
                                       </div>
                                   </div>
                               ))}
                           </div>
                       </div>

                       {/* CHAT COLUMN */}
                       <div className="lg:col-span-4 bg-[#e5ddd5] rounded-[3rem] shadow-xl overflow-hidden flex flex-col relative border border-slate-200 h-full max-h-[800px]">
