                  >
                     {isProcessing ? <Loader2 className="animate-spin" size={32} /> : <CheckCircle2 size={32} />}
                     {isProcessing ? 'İŞLENİYOR...' : 'SATIŞI TAMAMLA'}
                  </button>
               </div>
            </div>
         </div>
      </div>
    </div>
  );
};

